'use client';

import * as React from 'react';
import Link from 'next/link';
import { styled } from '@mui/material/styles';
import Drawer, { drawerClasses } from '@mui/material/Drawer';
import Box from '@mui/material/Box';
import Divider from '@mui/material/Divider';
import List from '@mui/material/List';
import ListSubheader from '@mui/material/ListSubheader';
import ListItemButton from '@mui/material/ListItemButton';
import ListItemIcon from '@mui/material/ListItemIcon';
import ListItemText from '@mui/material/ListItemText';
import Typography from '@mui/material/Typography';
import Avatar from '@mui/material/Avatar';
import Stack from '@mui/material/Stack';
import Button from '@mui/material/Button';
import Paper from '@mui/material/Paper';
import MenuItem from '@mui/material/MenuItem';
import Select from '@mui/material/Select';
import HomeRoundedIcon from '@mui/icons-material/HomeRounded';
import AnalyticsRoundedIcon from '@mui/icons-material/AnalyticsRounded';
import PeopleAltRoundedIcon from '@mui/icons-material/PeopleAltRounded';
import AssignmentRoundedIcon from '@mui/icons-material/AssignmentRounded';
import SettingsRoundedIcon from '@mui/icons-material/SettingsRounded';
import InfoRoundedIcon from '@mui/icons-material/InfoRounded';
import HelpOutlineRoundedIcon from '@mui/icons-material/HelpOutlineRounded';
import MoreVertRoundedIcon from '@mui/icons-material/MoreVertRounded';

export type NavItem = {
  label: string;
  href: string;
  icon: React.ReactNode;
};

export interface SideMenuProps {
  /**
   * ความกว้างของ Drawer (px)
   */
  width?: number;
  /**
   * path ปัจจุบัน (ไว้ทำ active state)
   */
  currentPath?: string;
  /**
   * รายการเมนูหลัก
   */
  mainItems?: NavItem[];
  /**
   * รายการเมนูรอง (Settings/About/Feedback)
   */
  secondaryItems?: NavItem[];
  /**
   * โปรเจ็กต์/เวิร์คสเปซที่เลือก
   */
  project?: string;
  projects?: string[];
  onProjectChange?: (value: string) => void;
}

const StyledDrawer = styled(Drawer)(({ theme }) => ({
  [`& .${drawerClasses.paper}`]: {
    borderRight: `1px solid ${theme.palette.divider}`,
  },
}));

const DEFAULT_MAIN: NavItem[] = [
  { label: 'Home', href: '/', icon: <HomeRoundedIcon /> },
  { label: 'Analytics', href: '/analytics', icon: <AnalyticsRoundedIcon /> },
  { label: 'Clients', href: '/clients', icon: <PeopleAltRoundedIcon /> },
  { label: 'Tasks', href: '/tasks', icon: <AssignmentRoundedIcon /> },
];

const DEFAULT_SECONDARY: NavItem[] = [
  { label: 'Settings', href: '/settings', icon: <SettingsRoundedIcon /> },
  { label: 'About', href: '/about', icon: <InfoRoundedIcon /> },
  { label: 'Feedback', href: '/feedback', icon: <HelpOutlineRoundedIcon /> },
];

export default function SideMenu({
  width = 240,
  currentPath = '/',
  mainItems = DEFAULT_MAIN,
  secondaryItems = DEFAULT_SECONDARY,
  project = 'Sitemark‑web',
  projects = ['Sitemark‑web', 'Mobile‑app', 'Admin‑console'],
  onProjectChange,
}: SideMenuProps) {
  return (
    <StyledDrawer
      variant="permanent"
      sx={{
        display: { xs: 'none', md: 'block' },
        width,
        flexShrink: 0,
        [`& .${drawerClasses.paper}`]: {
          width,
          boxSizing: 'border-box',
          bgcolor: 'background.default',
        },
      }}
    >
      {/* Header box (โปรเจ็กต์เซเลกต์) */}
      <Box sx={{ p: 2, pt: 2.5 }}>
        <Paper
          variant="outlined"
          sx={{
            p: 1.5,
            display: 'flex',
            alignItems: 'center',
            gap: 1.25,
            borderRadius: 2,
          }}
        >
          <Box
            sx={{
              width: 40,
              height: 28,
              borderRadius: 1.5,
              background:
                'linear-gradient(135deg, hsl(210 98% 60%) 0%, hsl(210 100% 35%) 100%)',
            }}
          />
          <Box sx={{ minWidth: 0, flex: 1 }}>
            <Typography variant="body2" sx={{ color: 'text.secondary', lineHeight: 1 }}>
              Web app
            </Typography>
            <Select
              size="small"
              fullWidth
              value={project}
              onChange={(e) => onProjectChange?.(String(e.target.value))}
              variant="outlined"
              sx={{
                mt: 0.25,
                '& .MuiOutlinedInput-notchedOutline': { border: 'none' },
                p: 0,
              }}
            >
              {projects.map((p) => (
                <MenuItem key={p} value={p}>
                  {p}
                </MenuItem>
              ))}
            </Select>
          </Box>
        </Paper>
      </Box>

      {/* เมนูหลัก */}
      <List sx={{ px: 1 }}>
        {mainItems.map((item) => {
          const active = currentPath === item.href;
          return (
            <ListItemButton
              key={item.href}
              component={Link}
              href={item.href}
              selected={active}
              sx={{
                borderRadius: 1.5,
                mx: 1,
                mb: 0.5,
              }}
            >
              <ListItemIcon sx={{ minWidth: 36 }}>{item.icon}</ListItemIcon>
              <ListItemText
                primary={item.label}
                primaryTypographyProps={{ fontWeight: active ? 600 : 500 }}
              />
            </ListItemButton>
          );
        })}
      </List>

      {/* เมนูรอง */}
      <List
        dense
        subheader={<ListSubheader disableSticky> </ListSubheader>}
        sx={{ px: 1, mt: 0.5 }}
      >
        {secondaryItems.map((item) => (
          <ListItemButton
            key={item.href}
            component={Link}
            href={item.href}
            sx={{ borderRadius: 1.5, mx: 1, mb: 0.25 }}
          >
            <ListItemIcon sx={{ minWidth: 36 }}>{item.icon}</ListItemIcon>
            <ListItemText primary={item.label} />
          </ListItemButton>
        ))}
      </List>

      {/* การ์ดโปรโมชัน/แจ้งเตือน */}
      <Box sx={{ px: 2, mt: 1.5 }}>
        <Paper variant="outlined" sx={{ p: 2, borderRadius: 2 }}>
          <Typography variant="subtitle2" sx={{ fontWeight: 700, mb: 0.5 }}>
            ✨ Plan about to expire
          </Typography>
          <Typography variant="body2" sx={{ color: 'text.secondary', mb: 1.5 }}>
            Enjoy 10% off when renewing your plan today.
          </Typography>
          <Button fullWidth variant="contained" size="small">
            Get the discount
          </Button>
        </Paper>
      </Box>

      {/* โปรไฟล์ผู้ใช้ (ล่างสุด) */}
      <Stack
        direction="row"
        alignItems="center"
        sx={{
          mt: 'auto',
          p: 2,
          gap: 1,
          borderTop: '1px solid',
          borderColor: 'divider',
        }}
      >
        <Avatar alt="Riley Carter" src="/static/images/avatar/7.jpg" sx={{ width: 36, height: 36 }} />
        <Box sx={{ minWidth: 0 }}>
          <Typography variant="body2" fontWeight={600} noWrap>
            Riley Carter
          </Typography>
          <Typography variant="caption" sx={{ color: 'text.secondary' }} noWrap>
            riley@email.com
          </Typography>
        </Box>
        <Box sx={{ ml: 'auto' }}>
          <MoreVertRoundedIcon fontSize="small" />
        </Box>
      </Stack>
    </StyledDrawer>
  );
}