'use client';

import * as React from 'react';
import type { Metadata } from 'next';
import { CssBaseline, ThemeProvider, createTheme, Box, Container } from '@mui/material';
import AppNavbar from './components/AppNavbar';
import SideMenu from './components/SideMenu';

// ปรับ path ตรงนี้ให้ชี้ไปที่ไฟล์ของคุณ

const theme = createTheme({
  // คุณจะใส่ palette/typography/customizations เพิ่มได้ที่นี่
});

export default function RootLayout({ children }: { children: React.ReactNode }) {
  return (
    <html lang="th">
      <body>
        <ThemeProvider theme={theme}>
          <CssBaseline />

          {/* แถบด้านบน: โชว์เฉพาะจอเล็ก (ภายใน AppNavbar มี sx กำหนดแล้ว) */}
          <AppNavbar />

          {/* โครงหลัก: ด้านซ้ายเป็น SideMenu (แสดง md up), ด้านขวาเป็นเนื้อหา */}
          <Box
            sx={{
              display: 'flex',
              minHeight: '100dvh',
              bgcolor: 'background.default',
            }}
          >
            {/* Sidebar (md up) */}
            <SideMenu />

            {/* Main content */}
            <Box
              component="main"
              sx={{
                flex: 1,
                display: 'flex',
                flexDirection: 'column',
                // เผื่อ space สำหรับ AppBar บน mobile (AppNavbar สูง ~ var(--template-frame-height))
                mt: { xs: 'calc(var(--template-frame-height, 56px))', md: 0 },
                p: { xs: 2, md: 3 },
                gap: 2,
              }}
            >
              <Container maxWidth="lg" sx={{ px: { xs: 0, sm: 2 } }}>
                {children}
              </Container>
            </Box>
          </Box>
        </ThemeProvider>
      </body>
    </html>
  );
}